import { GoogleGenAI } from "@google/genai";

// Initialize the Gemini API client
const apiKey = process.env.API_KEY || ''; // Ideally strictly from env
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const generateEnquiryDraft = async (
  eventType: string,
  stylePreference: string,
  guestCount: string
): Promise<string> => {
  if (!ai) {
    console.warn("Gemini API Key is missing. Returning fallback text.");
    return `I am interested in booking a ${eventType} session. We are expecting around ${guestCount} guests and love a ${stylePreference} style.`;
  }

  try {
    const model = ai.models;
    const prompt = `
      Write a polite, professional, and enthusiastic enquiry email for a photographer.
      Context:
      - Event Type: ${eventType}
      - Style Preference: ${stylePreference}
      - Estimated Guests/Scale: ${guestCount}

      Keep it short, under 100 words. Do not include subject lines or placeholders.
    `;

    const response = await model.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || '';
  } catch (error) {
    console.error("Error generating draft:", error);
    return `Hi, I'd love to enquire about your photography services for my ${eventType}. We are planning for ${guestCount} people and really enjoy your ${stylePreference} style. Looking forward to hearing from you.`;
  }
};

