export const Hero: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 6000);
    return () => clearInterval(timer);
  }, []);

  const toggleAudio = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => console.log("Audio play failed interaction required", e));
      }
      setIsPlaying(!isPlaying);
    }
  };

  const nextSlide = () => setCurrentSlide((prev) => (prev + 1) % slides.length);
  const prevSlide = () => setCurrentSlide((prev) => (prev - 1 + slides.length) % slides.length);

  return (
    <section className="relative h-screen w-full overflow-hidden bg-stone-900">
      {/* Audio Element */}
      <audio ref={audioRef} loop>
        <source src="https://assets.mixkit.co/music/preview/mixkit-dreaming-big-31.mp3" type="audio/mp3" />
      </audio>

      {/* Slider */}
      {slides.map((slide, index) => (
        <div
          key={slide.id}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === currentSlide ? 'opacity-100' : 'opacity-0'
          }`}
        >
          <div className="absolute inset-0 bg-black/30 z-10" />
          <img
            src={slide.imageUrl}
            alt={slide.title}
            className={`w-full h-full object-cover transition-transform duration-[8000ms] ease-out ${
                index === currentSlide ? 'scale-105' : 'scale-100'
            }`}
          />

          <div className="absolute inset-0 z-20 flex flex-col items-center justify-center text-center text-white px-4">
            <h2 className={`font-sans text-sm md:text-base tracking-[0.3em] uppercase mb-4 transition-all duration-1000 delay-300 ${
                 index === currentSlide ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
            }`}>
              {slide.subtitle}
            </h2>
            <h1 className={`font-display text-5xl md:text-7xl lg:text-9xl mb-8 transition-all duration-1000 delay-500 ${
                 index === currentSlide ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
            }`}>
              {slide.title}
            </h1>
          </div>
        </div>
      ))}

      {/* Controls */}
      <div className="absolute bottom-12 left-0 w-full z-30 px-6 md:px-12 flex justify-between items-center text-white">
        <div className="flex gap-4">
          <button 
            onClick={prevSlide}
            className="p-3 border border-white/20 hover:bg-white/10 rounded-full backdrop-blur-sm transition-all"
            aria-label="Previous Slide"
          >
            <ArrowLeft size={20} />
          </button>
          <button 
            onClick={nextSlide}
            className="p-3 border border-white/20 hover:bg-white/10 rounded-full backdrop-blur-sm transition-all"
            aria-label="Next Slide"
          >
            <ArrowRight size={20} />
          </button>
        </div>

        <button
          onClick={toggleAudio}
          className="flex items-center gap-2 text-sm tracking-widest uppercase hover:text-stone-300 transition-colors"
        >
          {isPlaying ? <Volume2 size={20} /> : <VolumeX size={20} />}
          <span className="hidden md:inline">{isPlaying ? 'Sound On' : 'Sound Off'}</span>
        </button>
      </div>

      {/* Progress Bar */}
      <div className="absolute bottom-0 left-0 w-full h-1 bg-white/10 z-30">
         <div 
           className="h-full bg-white transition-all duration-500 ease-out"
           style={{ width: `${((currentSlide + 1) / slides.length) * 100}%` }}
         />
      </div>
    </section>
  );
};

