interface GroupGalleryProps {
  group: Group;
  onBack: () => void;
}

export const GroupGallery: React.FC<GroupGalleryProps> = ({ group, onBack }) => {
  const [slideshowOpen, setSlideshowOpen] = useState(false);
  const [initialSlide, setInitialSlide] = useState(0);

  const openSlide = (index: number) => {
    setInitialSlide(index);
    setSlideshowOpen(true);
  };

  return (
    <div className="min-h-screen bg-stone-50 pt-32 pb-24 animate-fade-in">
      <div className="container mx-auto px-6">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-stone-500 hover:text-stone-900 transition-colors mb-12 uppercase text-xs tracking-widest"
        >
          <ArrowLeft size={16} /> Back to Collection
        </button>

        <header className="mb-20 max-w-4xl">
          <span className="block text-stone-400 uppercase tracking-[0.2em] text-sm mb-4">{group.location} — {group.date}</span>
          <h1 className="font-serif text-5xl md:text-7xl text-stone-900 mb-8">{group.title}</h1>
          <p className="font-sans text-stone-600 text-lg leading-relaxed max-w-2xl border-l border-stone-300 pl-6">
            {group.description}
          </p>
        </header>

        {/* Magazine Grid Layout */}
        <div className="grid grid-cols-1 md:grid-cols-12 gap-4 md:gap-8 auto-rows-[200px] md:auto-rows-[400px]">
          {group.images.map((img, index) => {
             // Dynamic layout logic based on index
             const isLarge = index % 5 === 0;
             const isTall = index % 5 === 2;

             let gridClass = "md:col-span-4"; // Default
             if (isLarge) gridClass = "md:col-span-8 md:row-span-2";
             if (isTall) gridClass = "md:col-span-4 md:row-span-2";

            return (
              <div 
                key={img.id}
                className={`relative group overflow-hidden cursor-pointer bg-stone-200 ${gridClass}`}
                onClick={() => openSlide(index)}
              >
                <img 
                  src={img.url} 
                  alt={img.caption}
                  loading="lazy" 
                  className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors duration-300" />
              </div>
            );
          })}
        </div>

        <Slideshow 
          images={group.images}
          isOpen={slideshowOpen}
          onClose={() => setSlideshowOpen(false)}
          initialIndex={initialSlide}
        />
      </div>
    </div>
  );
