  | { type: 'all-collections' }
  | { type: 'collection-detail'; collectionId: number }
  | { type: 'group-detail'; groupId: number; fromCollectionId: number }
  | { type: 'admin' };

/**
 * Mock Database Persistence Layer
 * Simulates a real backend database storage
 */

export const db = {
  save: <T>(key: string, data: T): void => {
    try {
      const existing = db.getAll<T>(key);
      const updated = [...existing, { ...data, id: Date.now(), createdAt: new Date().toISOString() }];
      localStorage.setItem(`lumina_${key}`, JSON.stringify(updated));
    } catch (e) {
      console.error('Database write error:', e);
    }
  },

  updateAll: <T>(key: string, data: T[]): void => {
    try {
      localStorage.setItem(`lumina_${key}`, JSON.stringify(data));
    } catch (e) {
      console.error('Database overwrite error:', e);
    }
  },

  getAll: <T>(key: string): T[] => {
    try {
      const data = localStorage.getItem(`lumina_${key}`);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error('Database read error:', e);
      return [];
    }
  },

  // Simulates network latency for a realistic "backend" feel
  simulateNetwork: (ms = 500) => new Promise(resolve => setTimeout(resolve, ms))
};

import { db } from './storage';
import { portfolioData as seedData } from '../data';
import { CollectionItem, Group } from '../types';

const STORAGE_KEY = 'portfolio_collections';

export const portfolioService = {
  /**
   * Initializes data if empty, then returns all collections
   */
  getCollections: async (): Promise<CollectionItem[]> => {
    await db.simulateNetwork(400);
    let data = db.getAll<CollectionItem>(STORAGE_KEY);

    if (data.length === 0) {
      // Seed with initial data from data.ts
      db.updateAll(STORAGE_KEY, seedData);
      return seedData;
    }

    return data;
  },

  /**
   * Save a new collection
   */
  createCollection: async (collection: Omit<CollectionItem, 'id' | 'groups'>): Promise<CollectionItem> => {
    await db.simulateNetwork(800);
    const collections = db.getAll<CollectionItem>(STORAGE_KEY);
    const newCollection: CollectionItem = {
      ...collection,
      id: Date.now(),
      groups: []
    };
    db.updateAll(STORAGE_KEY, [...collections, newCollection]);
    return newCollection;
  },

  /**
   * Add a group to an existing collection
   */
  addGroup: async (collectionId: number, group: Omit<Group, 'id'>): Promise<Group> => {
    await db.simulateNetwork(600);
    const collections = db.getAll<CollectionItem>(STORAGE_KEY);
    const index = collections.findIndex(c => c.id === collectionId);

    if (index === -1) throw new Error("Collection not found");

    const newGroup: Group = {
      ...group,
      id: Date.now()
    };

    collections[index].groups.push(newGroup);
    db.updateAll(STORAGE_KEY, collections);
    return newGroup;
  },

  /**
   * Delete a collection
   */
  deleteCollection: async (id: number): Promise<void> => {
    await db.simulateNetwork(500);
    const collections = db.getAll<CollectionItem>(STORAGE_KEY);
    db.updateAll(STORAGE_KEY, collections.filter(c => c.id !== id));
  }
};

