import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { Collections } from './components/Collections';
import { Features } from './components/Features';
import { Testimonials } from './components/Testimonials';
import { Pricing } from './components/Pricing';
import { Enquiry } from './components/Enquiry';
import { Footer } from './components/Footer';
import { AllCollections } from './components/AllCollections';
import { CollectionGroups } from './components/CollectionGroups';
import { GroupGallery } from './components/GroupGallery';
import { Admin } from './components/Admin';
import { ViewState, CollectionItem } from './types';
import { portfolioService } from './services/portfolioService';

function App() {
  const [viewState, setViewState] = useState<ViewState>({ type: 'home' });
  const [collections, setCollections] = useState<CollectionItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Initialize "Backend" Data Fetch
  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await portfolioService.getCollections();
        setCollections(data);
      } catch (err) {
        console.error("Backend fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [viewState.type]); // Refresh when coming back from admin

  // Reset scroll on view change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [viewState.type]);

  const handleNavigateHome = () => setViewState({ type: 'home' });

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-screen w-full flex flex-col items-center justify-center bg-stone-50">
          <div className="w-12 h-12 border-2 border-stone-200 border-t-stone-900 rounded-full animate-spin mb-6" />
          <p className="font-display text-xs tracking-[0.3em] uppercase opacity-40">Initializing Lumina Studio</p>
        </div>
      );
    }

    if (viewState.type === 'admin') {
      return <Admin onExit={handleNavigateHome} />;
    }

    switch (viewState.type) {
      case 'home':
        return (
          <main>
            <Hero />
            <Collections 
              collections={collections}
              onViewAll={() => setViewState({ type: 'all-collections' })}
              onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
            />
            <Features />
            <Testimonials />
            <Pricing />
            <Enquiry />
          </main>
        );

      case 'all-collections':
        return (
          <AllCollections 
            collections={collections}
            onBack={() => setViewState({ type: 'home' })}
            onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
          />
        );

      case 'collection-detail':
        const collection = collections.find(c => c.id === viewState.collectionId);
        if (!collection) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Collection not found</div>;
        return (
          <CollectionGroups 
            collection={collection}
            onBack={() => setViewState({ type: 'all-collections' })}
            onSelectGroup={(groupId) => setViewState({ 
              type: 'group-detail', 
              groupId, 
              fromCollectionId: collection.id 
            })}
          />
        );

      case 'group-detail':
         const parentCollection = collections.find(c => c.id === viewState.fromCollectionId);
         const group = parentCollection?.groups.find(g => g.id === viewState.groupId);
         if (!group) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Group not found</div>;
         return (
           <GroupGallery 
             group={group}
             onBack={() => setViewState({ type: 'collection-detail', collectionId: viewState.fromCollectionId })}
           />
         );

      default:
        return <div className="pt-40 text-center uppercase tracking-widest text-xs">Page not found</div>;
    }
  };

  return (
    <div className="font-sans antialiased bg-stone-50 min-h-screen">
      {viewState.type !== 'admin' && <Navbar onNavigateHome={handleNavigateHome} />}
      {renderContent()}
      {viewState.type !== 'admin' && <Footer onNavigateAdmin={() => setViewState({ type: 'admin' })} />}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { pricingService } from '../services/pricingService';
import { PricingTier } from '../types';
import { Check, ChevronLeft, ChevronRight } from 'lucide-react';

export const Pricing: React.FC = () => {
  const [tiers, setTiers] = useState<PricingTier[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    pricingService.getAll().then(setTiers);
  }, []);

  const handleScroll = () => {
    if (!scrollRef.current) return;
    const scrollLeft = scrollRef.current.scrollLeft;
    const width = scrollRef.current.offsetWidth;
    // Calculate index based on which item is most visible
    const newIndex = Math.round(scrollLeft / width);
    setActiveIndex(newIndex);
  };

  const scrollTo = (index: number) => {
    if (!scrollRef.current) return;
    const width = scrollRef.current.offsetWidth;
    scrollRef.current.scrollTo({
      left: width * index,
      behavior: 'smooth'
    });
  };

  if (tiers.length === 0) return null;

  return (
    <section id="pricing" className="py-32 bg-stone-50 overflow-hidden">
      <div className="container mx-auto px-6">
        <div className="text-center mb-20">
          <span className="text-stone-500 text-xs uppercase tracking-[0.2em] mb-4 block">Investment</span>
          <h2 className="font-serif text-5xl md:text-6xl text-stone-900 mb-6">Collections & Rates</h2>
        </div>

        <div className="relative max-w-7xl mx-auto">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory scrollbar-hide gap-6 pb-12"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {tiers.map((tier, idx) => (
              <div 
                key={tier.name + idx} 
                className="min-w-full md:min-w-[calc(33.333%-1rem)] snap-center"
              >
                <div className={`relative h-full p-10 border transition-all duration-500 flex flex-col ${tier.recommended ? 'border-stone-900 bg-stone-900 text-stone-50 shadow-xl scale-100' : 'border-stone-200 bg-white text-stone-900 shadow-sm hover:border-stone-400'}`}>
                  {tier.recommended && (
                    <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-stone-200 text-stone-900 text-[10px] font-bold px-4 py-1 uppercase tracking-widest">
                      Most Popular
                    </div>
                  )}
                  <h3 className="font-display text-xl uppercase tracking-widest mb-4 opacity-80">{tier.name}</h3>
                  <div className="flex items-baseline mb-8 pb-8 border-b border-current border-opacity-20">
                    <span className="text-5xl font-serif">{tier.price}</span>
                    <span className="ml-2 text-xs uppercase tracking-wide opacity-60">/ starting</span>
                  </div>
                  <ul className="space-y-5 mb-10 flex-grow">
                    {tier.features.map((feature, i) => (
                      <li key={i} className="flex items-start gap-4 text-sm opacity-80">
                        <Check size={14} className="mt-0.5 shrink-0" /> <span>{feature}</span>
                      </li>
                    ))}
                  </ul>
                  <button className={`w-full py-4 text-xs uppercase tracking-[0.2em] border transition-all ${tier.recommended ? 'bg-white text-stone-900 border-transparent hover:bg-stone-200' : 'bg-transparent text-stone-900 border-stone-900 hover:bg-stone-900 hover:text-white'}`}>
                    Select Package
                  </button>
                </div>
              </div>
            ))}
          </div>

          {/* Navigation Controls */}
          <div className="flex items-center justify-center gap-8 mt-4">
            <button 
              onClick={() => scrollTo(activeIndex - 1)}
              disabled={activeIndex === 0}
              className="p-2 text-stone-400 hover:text-stone-900 disabled:opacity-20 transition-all"
            >
              <ChevronLeft size={24} />
            </button>

            {/* Indicators */}
            <div className="flex gap-3">
              {/* On mobile we have tiers.length dots, on desktop we have fewer dots if we show 3 at once */}
              {/* Simplification: Just show dots for each item since swiping is item by item */}
              {tiers.map((_, i) => (
                <button
                  key={i}
                  onClick={() => scrollTo(i)}
                  className={`h-1.5 transition-all duration-500 rounded-full ${activeIndex === i ? 'w-8 bg-stone-900' : 'w-2 bg-stone-300'}`}
                  aria-label={`Go to slide ${i + 1}`}
                />
              ))}
            </div>

            <button 
              onClick={() => scrollTo(activeIndex + 1)}
              disabled={activeIndex === tiers.length - 1}
              className="p-2 text-stone-400 hover:text-stone-900 disabled:opacity-20 transition-all"
            >
              <ChevronRight size={24} />
            </button>
          </div>
        </div>
      </div>
    </section>
  );
};

import React, { useState, useEffect } from 'react';
