import React, { useState, useEffect, useRef } from 'react';
import { Quote, ChevronLeft, ChevronRight, Star } from 'lucide-react';
import { testimonialService, ExtendedTestimonial } from '../services/testimonialService';

export const Testimonials: React.FC = () => {
  const [data, setData] = useState<ExtendedTestimonial[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    testimonialService.getAll().then(setData);
  }, []);

  const handleScroll = () => {
    if (!scrollRef.current) return;
    const scrollLeft = scrollRef.current.scrollLeft;
    const width = scrollRef.current.offsetWidth;
    const newIndex = Math.round(scrollLeft / width);
    setActiveIndex(newIndex);
  };

  const scrollTo = (index: number) => {
    if (!scrollRef.current) return;
    const width = scrollRef.current.offsetWidth;
    scrollRef.current.scrollTo({
      left: width * index,
      behavior: 'smooth'
    });
  };

  if (!data.length) return null;

  return (
    <section className="py-32 bg-white relative overflow-hidden">
      <div className="absolute top-0 right-0 w-1/3 h-full bg-stone-50 -z-10" />
      <div className="container mx-auto px-6">
        <div className="relative">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory scrollbar-hide"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {data.map((item, idx) => (
              <div key={item.id} className="min-w-full snap-center py-10">
                <div className="flex flex-col lg:flex-row items-center gap-16 lg:gap-24">
                  {/* Image Part */}
                  <div className="w-full lg:w-5/12 relative group">
                    <div className="aspect-[3/4] overflow-hidden relative z-10 bg-stone-200 shadow-2xl">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-stone-900/10" />
                    </div>
                    <div className="absolute -bottom-6 -right-6 w-24 h-24 bg-stone-900 z-20 flex items-center justify-center text-white">
                      <Quote size={32} />
                    </div>
                  </div>

                  {/* Text Part */}
                  <div className="w-full lg:w-7/12 space-y-8">
                    <div>
                      <div className="flex gap-1 text-stone-900 mb-6">
                        {[...Array(item.rating)].map((_, i) => (
                          <Star key={i} size={16} fill="currentColor" strokeWidth={0} />
                        ))}
                      </div>
                      <blockquote className="min-h-[160px]">
                        <p className="font-serif text-3xl md:text-4xl leading-tight text-stone-900 italic">
                          "{item.quote}"
                        </p>
                      </blockquote>
                      <div className="pt-8 border-t border-stone-200">
                        <h4 className="font-display text-xl uppercase tracking-widest text-stone-900">
                          {item.name}
                        </h4>
                        <p className="font-sans text-stone-500 text-sm tracking-wide mt-1">
                          {item.role}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Navigation Controls */}
          <div className="flex items-center justify-center lg:justify-start lg:ml-[45%] gap-8 mt-12">
            <button 
              onClick={() => scrollTo(activeIndex - 1)}
              disabled={activeIndex === 0}
              className="p-4 border border-stone-200 hover:bg-stone-900 hover:text-white disabled:opacity-20 transition-all"
            >
              <ChevronLeft size={20} />
            </button>

            {/* Indicators */}
            <div className="flex gap-3">
              {data.map((_, i) => (
                <button
                  key={i}
                  onClick={() => scrollTo(i)}
                  className={`h-1.5 transition-all duration-500 rounded-full ${activeIndex === i ? 'w-8 bg-stone-900' : 'w-2 bg-stone-300'}`}
                />
              ))}
            </div>

            <button 
              onClick={() => scrollTo(activeIndex + 1)}
              disabled={activeIndex === data.length - 1}
              className="p-4 border border-stone-200 hover:bg-stone-900 hover:text-white disabled:opacity-20 transition-all"
            >
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      </div>
    </section>
  );
};

import React from 'react';
import { ArrowUpRight, Grid } from 'lucide-react';
import { CollectionItem, ImageItem } from '../types';

interface CollectionsProps {
  onViewAll: () => void;
  onSelectCollection: (id: number) => void;
  collections: any[];
}

export const Collections: React.FC<CollectionsProps> = ({ onViewAll, onSelectCollection, collections }) => {
  // Only show collections marked as featured in the backend
  const featured = collections
    .filter(c => c.isFeatured)
    .sort((a, b) => (a.order || 0) - (b.order || 0));

  const getImages = (collection: CollectionItem): ImageItem[] => {
    if (!collection.groups.length) return [];
    const images = collection.groups.flatMap(g => [g.previewImages[0], g.previewImages[1]]).filter(Boolean);
    if (images.length < 3) return [...images, ...collection.groups[0].images.slice(0, 3 - images.length)];
    return images;
  };

  return (
