export const testimonialService = {
  getAll: async (): Promise<ExtendedTestimonial[]> => {
    await db.simulateNetwork(300);
    let data = db.getAll<ExtendedTestimonial>(STORAGE_KEY);
    if (data.length === 0) {
      db.updateAll(STORAGE_KEY, initialTestimonials);
      return initialTestimonials;
    }
    // Ensure we always have at least the seed data if somehow empty or for first-time refresh
    return data.sort((a, b) => a.order - b.order);
  },

  updateAll: async (data: ExtendedTestimonial[]) => {
    await db.simulateNetwork(500);
    db.updateAll(STORAGE_KEY, data);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Quote, ChevronLeft, ChevronRight, Star } from 'lucide-react';
import { testimonialService, ExtendedTestimonial } from '../services/testimonialService';

export const Testimonials: React.FC = () => {
  const [data, setData] = useState<ExtendedTestimonial[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    testimonialService.getAll().then(setData);
  }, []);

  const handleScroll = () => {
    if (!scrollRef.current) return;
    const scrollLeft = scrollRef.current.scrollLeft;
    const width = scrollRef.current.offsetWidth;
    const newIndex = Math.round(scrollLeft / width);
    setActiveIndex(newIndex);
  };

  const scrollTo = (index: number) => {
    if (!scrollRef.current || data.length === 0) return;
    const safeIndex = Math.max(0, Math.min(index, data.length - 1));
    const width = scrollRef.current.offsetWidth;
    scrollRef.current.scrollTo({
      left: width * safeIndex,
      behavior: 'smooth'
    });
  };

  if (!data.length) return null;

  return (
    <section className="py-32 bg-white relative overflow-hidden">
      <div className="absolute top-0 right-0 w-1/3 h-full bg-stone-50 -z-10" />
      <div className="container mx-auto px-6">
        <div className="relative">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory scrollbar-hide no-scrollbar"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {data.map((item, idx) => (
              <div key={item.id} className="min-w-full snap-center py-10 px-4 md:px-0">
                <div className="flex flex-col lg:flex-row items-center gap-12 lg:gap-24 max-w-6xl mx-auto">
                  {/* Image Part */}
                  <div className="w-full lg:w-5/12 relative group shrink-0">
                    <div className="aspect-[3/4] overflow-hidden relative z-10 bg-stone-200 shadow-2xl transition-transform duration-700 group-hover:scale-[1.02]">
                      <img 
                        src={item.image} 
                        alt={item.name} 
                        className="w-full h-full object-cover grayscale-[30%] group-hover:grayscale-0 transition-all duration-700" 
                      />
                      <div className="absolute inset-0 bg-stone-900/10" />
                    </div>
                    <div className="absolute -bottom-6 -right-6 w-16 h-16 md:w-24 md:h-24 bg-stone-900 z-20 flex items-center justify-center text-white shadow-xl">
                      <Quote size={window.innerWidth < 768 ? 20 : 32} />
                    </div>
                  </div>

                  {/* Text Part */}
                  <div className="w-full lg:w-7/12 space-y-8 flex flex-col justify-center">
                    <div>
                      <div className="flex gap-1 text-stone-900 mb-6">
                        {[...Array(item.rating)].map((_, i) => (
                          <Star key={i} size={16} fill="currentColor" strokeWidth={0} />
                        ))}
                      </div>
                      <blockquote className="min-h-[140px] md:min-h-[180px]">
                        <p className="font-serif text-2xl md:text-4xl leading-tight text-stone-900 italic">
                          "{item.quote}"
                        </p>
                      </blockquote>
                      <div className="pt-8 border-t border-stone-200 flex items-center justify-between">
                        <div>
                          <h4 className="font-display text-xl uppercase tracking-widest text-stone-900">
                            {item.name}
                          </h4>
                          <p className="font-sans text-stone-500 text-sm tracking-wide mt-1">
                            {item.role}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Navigation Controls */}
          <div className="flex items-center justify-center lg:justify-start lg:ml-[45%] gap-8 mt-12">
            <button 
              onClick={() => scrollTo(activeIndex - 1)}
              disabled={activeIndex === 0}
              className="p-4 border border-stone-200 hover:bg-stone-900 hover:text-white disabled:opacity-20 transition-all active:scale-95"
              aria-label="Previous testimonial"
            >
              <ChevronLeft size={20} />
            </button>

            {/* Indicators */}
            <div className="flex gap-3">
              {data.map((_, i) => (
                <button
                  key={i}
                  onClick={() => scrollTo(i)}
                  className={`h-1.5 transition-all duration-500 rounded-full ${activeIndex === i ? 'w-8 bg-stone-900' : 'w-2 bg-stone-300'}`}
                  aria-label={`Go to testimonial ${i + 1}`}
                />
              ))}
            </div>

            <button 
              onClick={() => scrollTo(activeIndex + 1)}
              disabled={activeIndex === data.length - 1}
              className="p-4 border border-stone-200 hover:bg-stone-900 hover:text-white disabled:opacity-20 transition-all active:scale-95"
              aria-label="Next testimonial"
            >
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      </div>
      <style>{`
        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
        .scrollbar-hide {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </section>
  );
};

