import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { Collections } from './components/Collections';
import { Features } from './components/Features';
import { Testimonials } from './components/Testimonials';
import { Pricing } from './components/Pricing';
import { Enquiry } from './components/Enquiry';
import { Footer } from './components/Footer';
import { AllCollections } from './components/AllCollections';
import { CollectionGroups } from './components/CollectionGroups';
import { GroupGallery } from './components/GroupGallery';
import { Admin } from './components/Admin';
import { ViewState, CollectionItem } from './types';
import { portfolioService } from './services/portfolioService';

function App() {
  const [viewState, setViewState] = useState<ViewState>({ type: 'home' });
  const [collections, setCollections] = useState<CollectionItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState(localStorage.getItem('theme') || 'light');

  // Initialize Theme
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // Initialize "Backend" Data Fetch
  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await portfolioService.getCollections();
        setCollections(data);
      } catch (err) {
        console.error("Backend fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [viewState.type]);

  // Reset scroll on view change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [viewState.type]);

  const handleNavigateHome = () => setViewState({ type: 'home' });

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-screen w-full flex flex-col items-center justify-center bg-stone-50 dark:bg-stone-950">
          <div className="w-12 h-12 border-2 border-stone-200 dark:border-stone-800 border-t-stone-900 dark:border-t-stone-100 rounded-full animate-spin mb-6" />
          <p className="font-display text-xs tracking-[0.3em] uppercase opacity-40 text-stone-900 dark:text-stone-100">Initializing Lumina Studio</p>
        </div>
      );
    }

    if (viewState.type === 'admin') {
      return <Admin onExit={handleNavigateHome} />;
    }

    switch (viewState.type) {
      case 'home':
        return (
          <main>
            <Hero />
            <Collections 
              collections={collections}
              onViewAll={() => setViewState({ type: 'all-collections' })}
              onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
            />
            <Features />
            <Testimonials />
            <Pricing />
            <Enquiry />
          </main>
        );

      case 'all-collections':
        return (
          <AllCollections 
            collections={collections}
            onBack={() => setViewState({ type: 'home' })}
            onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
          />
        );

      case 'collection-detail':
        const collection = collections.find(c => c.id === viewState.collectionId);
        if (!collection) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Collection not found</div>;
        return (
          <CollectionGroups 
            collection={collection}
            onBack={() => setViewState({ type: 'all-collections' })}
            onSelectGroup={(groupId) => setViewState({ 
              type: 'group-detail', 
              groupId, 
              fromCollectionId: collection.id 
            })}
          />
        );

      case 'group-detail':
         const parentCollection = collections.find(c => c.id === viewState.fromCollectionId);
         const group = parentCollection?.groups.find(g => g.id === viewState.groupId);
         if (!group) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Group not found</div>;
         return (
           <GroupGallery 
             group={group}
             onBack={() => setViewState({ type: 'collection-detail', collectionId: viewState.fromCollectionId })}
           />
         );

      default:
        return <div className="pt-40 text-center uppercase tracking-widest text-xs">Page not found</div>;
    }
  };

  return (
    <div className="font-sans antialiased bg-stone-50 dark:bg-stone-950 min-h-screen transition-colors duration-500">
      {viewState.type !== 'admin' && <Navbar onNavigateHome={handleNavigateHome} theme={theme} onToggleTheme={toggleTheme} />}
      {renderContent()}
      {viewState.type !== 'admin' && <Footer onNavigateAdmin={() => setViewState({ type: 'admin' })} />}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Menu, X, Camera, Sun, Moon } from 'lucide-react';

interface NavbarProps {
  onNavigateHome: () => void;
  theme: string;
  onToggleTheme: () => void;
}

export const Navbar: React.FC<NavbarProps> = ({ onNavigateHome, theme, onToggleTheme }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLinkClick = (href: string) => {
    setIsMenuOpen(false);
    onNavigateHome();
    setTimeout(() => {
       const element = document.querySelector(href);
       element?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const navLinks = [
    { name: 'Portfolio', href: '#portfolio' },
    { name: 'Philosophy', href: '#features' },
    { name: 'Pricing', href: '#pricing' },
    { name: 'Contact', href: '#enquiry' },
  ];

  return (
    <nav
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-500 ${
        isScrolled || isMenuOpen ? 'bg-stone-900 dark:bg-stone-950 text-stone-50 py-4 shadow-lg border-b border-stone-800' : 'bg-transparent text-white py-6'
      }`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        <button onClick={onNavigateHome} className="flex items-center gap-2 group">
          <Camera className="w-6 h-6" strokeWidth={1.5} />
          <span className="font-display text-2xl tracking-widest font-bold group-hover:text-stone-300 transition-colors">
            LUMINA
          </span>
        </button>

        {/* Desktop Menu */}
        <div className="hidden md:flex gap-8 items-center">
          {navLinks.map((link) => (
            <button
              key={link.name}
              onClick={() => handleLinkClick(link.href)}
              className="font-sans text-xs uppercase tracking-[0.2em] hover:text-stone-400 transition-colors relative after:content-[''] after:absolute after:bottom-[-4px] after:left-0 after:w-0 after:h-[1px] after:bg-current after:transition-all hover:after:w-full"
            >
              {link.name}
            </button>
          ))}

          <div className="flex items-center gap-4 ml-4">
            <button 
              onClick={onToggleTheme}
              className="p-2 rounded-full hover:bg-white/10 transition-all duration-500 group"
              aria-label="Toggle Theme"
            >
              {theme === 'light' ? (
                <Moon size={18} className="group-hover:rotate-[360deg] transition-transform duration-700" />
              ) : (
                <Sun size={18} className="group-hover:rotate-[360deg] transition-transform duration-700 text-champagne" />
              )}
            </button>
            <button
              onClick={() => handleLinkClick('#enquiry')}
              className={`border px-6 py-2 text-[10px] font-bold uppercase tracking-widest transition-all duration-300 border-white hover:bg-white hover:text-stone-900`}
            >
              Book Now
            </button>
          </div>
        </div>

        {/* Mobile Toggle */}
        <div className="flex items-center gap-4 md:hidden">
          <button onClick={onToggleTheme} className="p-2 rounded-full hover:bg-white/10 transition-colors">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} className="text-champagne" />}
          </button>
          <button
            className="text-inherit"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      <div
        className={`md:hidden fixed top-0 left-0 w-full h-screen bg-stone-900 dark:bg-stone-950 text-white flex flex-col items-center justify-center gap-8 transition-transform duration-500 ease-in-out z-40 ${
          isMenuOpen ? 'translate-y-0' : '-translate-y-full'
        }`}
      >
        <button
          className="absolute top-6 right-6"
          onClick={() => setIsMenuOpen(false)}
        >
          <X size={32} />
        </button>
        {navLinks.map((link) => (
          <button
            key={link.name}
            onClick={() => handleLinkClick(link.href)}
            className="font-display text-3xl hover:text-stone-400 transition-colors"
          >
            {link.name}
          </button>
        ))}
      </div>
    </nav>
  );
};

