import React, { useState, useEffect, useRef } from 'react';
import { Quote, ChevronLeft, ChevronRight, Star, CheckCircle2 } from 'lucide-react';
import { testimonialService, ExtendedTestimonial } from '../services/testimonialService';

export const Testimonials: React.FC = () => {
  const [data, setData] = useState<ExtendedTestimonial[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    testimonialService.getAll().then(setData);
  }, []);

  const handleScroll = () => {
    if (!scrollRef.current) return;
    const scrollLeft = scrollRef.current.scrollLeft;
    const width = scrollRef.current.offsetWidth;
    const newIndex = Math.round(scrollLeft / width);
    setActiveIndex(newIndex);
  };

  const scrollTo = (index: number) => {
    if (!scrollRef.current || data.length === 0) return;
    const safeIndex = Math.max(0, Math.min(index, data.length - 1));
    const width = scrollRef.current.offsetWidth;
    scrollRef.current.scrollTo({
      left: width * safeIndex,
      behavior: 'smooth'
    });
  };

  if (!data.length) return null;

  return (
    <section className="py-32 bg-stone-50 dark:bg-stone-950 relative overflow-hidden transition-colors duration-500">
      {/* Subtle Grain Texture Overlay */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.03] dark:opacity-[0.05] z-50 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]" />

