          <span className="absolute -top-10 -left-10 text-[15rem] font-serif text-stone-200/20 dark:text-stone-800/20 pointer-events-none select-none z-[-1]">T</span>
        </div>

        <div className="relative">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory scrollbar-hide no-scrollbar"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {data.map((item, idx) => (
              <div key={item.id} className="min-w-full snap-center py-10">
                <div className="flex flex-col lg:flex-row items-center gap-16 lg:gap-32 max-w-7xl mx-auto">

                  {/* Image Part with Studio Seal */}
                  <div className="w-full lg:w-5/12 relative group shrink-0">
                    <div className="aspect-[3/4] overflow-hidden relative z-10 bg-stone-200 dark:bg-stone-900 shadow-2xl transition-all duration-700">
                      <img 
                        src={item.image} 
                        alt={item.name} 
                        className="w-full h-full object-cover grayscale-[40%] group-hover:grayscale-0 transition-all duration-1000" 
                      />
                      <div className="absolute inset-0 bg-stone-900/10 group-hover:bg-transparent transition-colors duration-700" />
                    </div>

                    {/* Rotating Studio Seal (Trust Marker) */}
                    <div className="absolute -top-8 -right-8 w-32 h-32 z-30 hidden md:block animate-spin-slow">
                       <svg viewBox="0 0 100 100" className="w-full h-full">
                         <path id="circlePath" d="M 50, 50 m -37, 0 a 37,37 0 1,1 74,0 a 37,37 0 1,1 -74,0" fill="transparent" />
                         <text className="text-[9px] uppercase tracking-[0.2em] font-bold fill-stone-900 dark:fill-champagne">
                           <textPath xlinkHref="#circlePath">
                             • Verified Commission • Authentic Narrative • Verified Commission • Authentic Narrative
                           </textPath>
                         </text>
                       </svg>
                       <div className="absolute inset-0 flex items-center justify-center">
                          <CheckCircle2 size={24} className="text-stone-900 dark:text-champagne" />
                       </div>
                    </div>

                    <div className="absolute -bottom-8 -left-8 w-24 h-24 bg-stone-900 dark:bg-stone-800 z-20 flex items-center justify-center text-white dark:text-champagne shadow-2xl">
