export const Hero: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 8000);
    return () => clearInterval(timer);
  }, []);

  const toggleAudio = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => console.log("Audio play failed interaction required", e));
      }
      setIsPlaying(!isPlaying);
    }
  };

  const nextSlide = () => setCurrentSlide((prev) => (prev + 1) % slides.length);
  const prevSlide = () => setCurrentSlide((prev) => (prev - 1 + slides.length) % slides.length);

  return (
    <section className="relative h-screen w-full overflow-hidden bg-stone-900">
      <audio ref={audioRef} loop>
        <source src="https://assets.mixkit.co/music/preview/mixkit-dreaming-big-31.mp3" type="audio/mp3" />
      </audio>

      {slides.map((slide, index) => (
        <div
          key={slide.id}
          className={`absolute inset-0 transition-opacity duration-[1500ms] ease-in-out ${
            index === currentSlide ? 'opacity-100 z-10' : 'opacity-0 z-0'
          }`}
        >
          <div className="absolute inset-0 bg-black/40 z-10" />
          <img
            src={slide.imageUrl}
            alt={slide.title}
            className={`w-full h-full object-cover transition-transform duration-[10000ms] ease-linear ${
                index === currentSlide ? 'scale-110' : 'scale-100'
            }`}
          />

          <div className="absolute inset-0 z-20 flex flex-col items-center justify-center text-center text-white px-4">
            <h2 className={`font-sans text-xs md:text-sm tracking-[0.5em] uppercase mb-4 transition-all duration-[1200ms] cubic-bezier(0.16, 1, 0.3, 1) ${
                 index === currentSlide ? 'translate-y-0 opacity-100 tracking-[0.5em]' : 'translate-y-10 opacity-0 tracking-[1em]'
            }`}>
              {slide.subtitle}
            </h2>
            <h1 className={`font-display text-5xl md:text-7xl lg:text-[10rem] mb-8 leading-none transition-all duration-[1500ms] cubic-bezier(0.16, 1, 0.3, 1) delay-200 ${
                 index === currentSlide ? 'translate-y-0 opacity-100 scale-100' : 'translate-y-20 opacity-0 scale-95'
            }`}>
              {slide.title}
            </h1>
          </div>
        </div>
      ))}

      <div className="absolute bottom-12 left-0 w-full z-30 px-6 md:px-12 flex justify-between items-center text-white">
        <div className="flex gap-4">
          <button 
            onClick={prevSlide}
            className="p-4 border border-white/10 hover:bg-white hover:text-stone-950 rounded-full backdrop-blur-md transition-all duration-500 transform active:scale-90"
          >
            <ArrowLeft size={18} />
          </button>
          <button 
            onClick={nextSlide}
            className="p-4 border border-white/10 hover:bg-white hover:text-stone-950 rounded-full backdrop-blur-md transition-all duration-500 transform active:scale-90"
          >
            <ArrowRight size={18} />
          </button>
        </div>

        <button
          onClick={toggleAudio}
          className="flex items-center gap-3 text-[10px] tracking-[0.3em] font-bold uppercase hover:text-champagne transition-colors duration-500 group"
        >
          <div className="relative">
            {isPlaying ? <Volume2 size={18} /> : <VolumeX size={18} />}
            {isPlaying && <span className="absolute -top-1 -right-1 w-2 h-2 bg-champagne rounded-full animate-ping"></span>}
          </div>
          <span className="hidden md:inline">{isPlaying ? 'Ambient Audio On' : 'Ambient Audio Off'}</span>
        </button>
      </div>

      <div className="absolute bottom-0 left-0 w-full h-[2px] bg-white/5 z-30">
         <div 
           className="h-full bg-white/40 transition-all duration-[8000ms] ease-linear"
           style={{ width: `${((currentSlide + 1) / slides.length) * 100}%` }}
         />
      </div>
    </section>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Camera } from 'lucide-react';
import { Group, ImageItem } from '../types';
