interface GroupGalleryProps {
  group: Group;
  onBack: () => void;
}

const LazyImage: React.FC<{ 
  image: ImageItem; 
  index: number; 
  onClick: () => void 
}> = ({ image, index, onClick }) => {
  const [isIntersecting, setIntersecting] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);
  const imgRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIntersecting(true);
          observer.unobserve(entry.target);
        }
      },
      { rootMargin: '300px' }
    );

    if (imgRef.current) {
      observer.observe(imgRef.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <div 
      ref={imgRef}
      className="break-inside-avoid relative group cursor-pointer overflow-hidden bg-stone-100 dark:bg-stone-900/40 mb-4 md:mb-8 lg:mb-12 transition-all duration-700 hover:shadow-2xl perspective-card"
      onClick={onClick}
    >
      <div className={`relative overflow-hidden transition-all duration-1000 ${isLoaded ? 'opacity-100 scale-100' : 'opacity-0 scale-105'}`}>
        {isIntersecting && (
          <img 
            src={image.url} 
            alt={image.caption || `Gallery image ${index + 1}`}
            onLoad={() => setIsLoaded(true)}
            className={`w-full h-auto object-cover transition-all duration-[2s] ease-out group-hover:scale-110 grayscale-[10%] group-hover:grayscale-0 ${isLoaded ? 'shutter-image' : 'opacity-0'}`}
          />
        )}

        <div className="absolute inset-0 bg-stone-900/0 group-hover:bg-stone-900/20 transition-all duration-[1s] cubic-bezier(0.16, 1, 0.3, 1)" />

        <div className="absolute bottom-0 left-0 w-full p-4 md:p-8 translate-y-full group-hover:translate-y-0 transition-all duration-[0.8s] cubic-bezier(0.16, 1, 0.3, 1) bg-gradient-to-t from-black/80 via-black/20 to-transparent">
            <p className="text-[10px] font-bold tracking-[0.3em] text-white uppercase opacity-0 group-hover:opacity-100 transition-opacity duration-[1s] delay-200">
              {image.caption || "View Full Composition"}
            </p>
            <div className="w-0 group-hover:w-full h-px bg-white/30 mt-3 transition-all duration-[1s] delay-100"></div>
        </div>
      </div>

      {!isLoaded && (
        <div className="absolute inset-0 flex items-center justify-center bg-stone-100 dark:bg-stone-900/20 animate-pulse">
           <Camera size={24} className="text-stone-300 dark:text-stone-800" strokeWidth={1} />
        </div>
      )}
    </div>
  );
};

