import { db } from './storage';
import { portfolioData as seedData } from '../data';
import { CollectionItem, Group } from '../types';

const STORAGE_KEY = 'portfolio_collections';

export interface ExtendedCollection extends CollectionItem {
  isFeatured?: boolean;
  order?: number;
}

export const portfolioService = {
  getCollections: async (): Promise<ExtendedCollection[]> => {
    await db.simulateNetwork(400);
    let data = db.getAll<ExtendedCollection>(STORAGE_KEY);

    // Seed if empty
    if (data.length === 0) {
      const processed = seedData.map((c, i) => ({ 
        ...c, 
        isFeatured: true, // All seed items featured by default
        order: i 
      }));
      db.updateAll(STORAGE_KEY, processed);
      return processed;
    }

    // Repair logic: Ensure every item has an 'isFeatured' and 'order' property
    // This prevents items from "disappearing" if they were saved without these flags
    let needsRepair = false;
    const repairedData = data.map((c, i) => {
      if (c.isFeatured === undefined || c.order === undefined) {
        needsRepair = true;
        return { 
          ...c, 
          isFeatured: c.isFeatured ?? (i < 3), 
          order: c.order ?? i 
        };
      }
      return c;
    });

    if (needsRepair) {
      db.updateAll(STORAGE_KEY, repairedData);
      return repairedData.sort((a, b) => (a.order || 0) - (b.order || 0));
    }

    return data.sort((a, b) => (a.order || 0) - (b.order || 0));
  },

  updateCollection: async (collection: ExtendedCollection): Promise<void> => {
    await db.simulateNetwork(500);
    const collections = db.getAll<ExtendedCollection>(STORAGE_KEY);
    const index = collections.findIndex(c => c.id === collection.id);
    if (index !== -1) {
      collections[index] = collection;
      db.updateAll(STORAGE_KEY, collections);
    }
  },

  createCollection: async (collection: Omit<ExtendedCollection, 'id' | 'groups'>): Promise<ExtendedCollection> => {
    await db.simulateNetwork(800);
    const collections = db.getAll<ExtendedCollection>(STORAGE_KEY);
    const newCollection: ExtendedCollection = {
      ...collection,
      id: Date.now(),
      groups: [],
      isFeatured: false,
      order: collections.length
    };
    db.updateAll(STORAGE_KEY, [...collections, newCollection]);
    return newCollection;
  },

  deleteCollection: async (id: number): Promise<void> => {
    await db.simulateNetwork(500);
    const collections = db.getAll<ExtendedCollection>(STORAGE_KEY);
    db.updateAll(STORAGE_KEY, collections.filter(c => c.id !== id));
  }
};

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { Collections } from './components/Collections';
import { Features } from './components/Features';
import { Testimonials } from './components/Testimonials';
import { Equipment } from './components/Equipment';
import { Pricing } from './components/Pricing';
import { Enquiry } from './components/Enquiry';
import { Footer } from './components/Footer';
import { AllCollections } from './components/AllCollections';
import { CollectionGroups } from './components/CollectionGroups';
import { GroupGallery } from './components/GroupGallery';
import { Admin } from './components/Admin';
import { ViewState } from './types';
import { portfolioService, ExtendedCollection } from './services/portfolioService';

function App() {
  const [viewState, setViewState] = useState<ViewState>({ type: 'home' });
  const [collections, setCollections] = useState<ExtendedCollection[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState(localStorage.getItem('theme') || 'light');

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await portfolioService.getCollections();
        setCollections(data);
      } catch (err) {
        console.error("Backend fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [viewState.type]);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [viewState.type]);

  const handleNavigateHome = () => setViewState({ type: 'home' });

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-screen w-full flex flex-col items-center justify-center bg-stone-50 dark:bg-stone-950">
          <div className="w-12 h-12 border-2 border-stone-200 dark:border-stone-800 border-t-stone-900 dark:border-t-stone-100 rounded-full animate-spin mb-6" />
          <p className="font-display text-xs tracking-[0.3em] uppercase opacity-40 text-stone-900 dark:text-stone-100">Initializing Lumina Studio</p>
        </div>
      );
    }

    if (viewState.type === 'admin') {
      return <Admin onExit={handleNavigateHome} />;
    }

    return (
      <div key={viewState.type + (viewState.type === 'collection-detail' ? viewState.collectionId : '')} className="animate-premium-fade">
        {(() => {
          switch (viewState.type) {
            case 'home':
              return (
                <main>
                  <Hero />
                  <Collections 
                    collections={collections}
                    onViewAll={() => setViewState({ type: 'all-collections' })}
                    onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
                  />
                  <Features />
                  <Testimonials />
                  <Equipment />
                  <Pricing />
                  <Enquiry />
                </main>
              );

            case 'all-collections':
              return (
                <AllCollections 
                  collections={collections}
                  onBack={() => setViewState({ type: 'home' })}
                  onSelectCollection={(id) => setViewState({ type: 'collection-detail', collectionId: id })}
                />
              );

            case 'collection-detail':
              const collection = collections.find(c => c.id === viewState.collectionId);
              if (!collection) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Collection not found</div>;
              return (
                <CollectionGroups 
                  collection={collection}
                  onBack={() => setViewState({ type: 'all-collections' })}
                  onSelectGroup={(groupId) => setViewState({ 
                    type: 'group-detail', 
                    groupId, 
                    fromCollectionId: collection.id 
                  })}
                />
              );

            case 'group-detail':
               const parentCollection = collections.find(c => c.id === viewState.fromCollectionId);
               const group = parentCollection?.groups.find(g => g.id === viewState.groupId);
               if (!group) return <div className="pt-40 text-center uppercase tracking-widest text-xs">Group not found</div>;
               return (
                 <GroupGallery 
                   group={group}
                   onBack={() => setViewState({ type: 'collection-detail', collectionId: viewState.fromCollectionId })}
                 />
               );

            default:
              return <div className="pt-40 text-center uppercase tracking-widest text-xs">Page not found</div>;
          }
        })()}
      </div>
    );
  };

  return (
    <div className="font-sans antialiased bg-stone-50 dark:bg-stone-950 min-h-screen transition-colors duration-500 overflow-x-hidden">
      {viewState.type !== 'admin' && <Navbar onNavigateHome={handleNavigateHome} theme={theme} onToggleTheme={toggleTheme} currentView={viewState.type} />}
      {renderContent()}
      {viewState.type !== 'admin' && <Footer onNavigateAdmin={() => setViewState({ type: 'admin' })} />}
    </div>
  );
}

export default App;

